    from copy import deepcopy

    # Create a copy of the graph to avoid modifying the original
    graph_copy = deepcopy(graph_data)

    # Find the parent node 'ju1.a3.dom' by checking node name and type
    parent_node = None
    for node, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.a3.dom' and 'EK_CONTROL_DOMAIN' in attrs.get('type', []):
            parent_node = node
            break

    if parent_node is None:
        return {
            'type': 'text',
            'data': 'Parent node ju1.a3.dom not found.',
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Create the new PORT node
    new_port_name = 'new_EK_PORT_55'
    new_port_node = {
        'name': new_port_name,
        'type': ['EK_PORT'],
        'physical_capacity_bps': 1000000000  # Default capacity, can be adjusted as needed
    }
    graph_copy.add_node(new_port_name, **new_port_node)

    # Add edge from parent to new port
    graph_copy.add_edge(parent_node, new_port_name, type='RK_CONTAINS')

    # Find all direct child PORT nodes of 'ju1.a3.dom' (direct children are those connected via RK_CONTAINS)
    direct_children = []
    for neighbor in graph_copy.neighbors(parent_node):
        neighbor_attrs = graph_copy.nodes[neighbor]
        if 'EK_PORT' in neighbor_attrs.get('type', []):
            direct_children.append((neighbor, neighbor_attrs.get('physical_capacity_bps', 0)))

    # Sort children by physical_capacity_bps in descending order
    direct_children.sort(key=lambda x: x[1], reverse=True)

    # Prepare return data
    return {
        'type': 'list',
        'data': direct_children,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

